from typing import TypedDict
from langgraph.graph import StateGraph, END

class QueryState(TypedDict):
    query: str
    route: str
    response: str

def classify_node(state: QueryState) -> QueryState:
    route = semantic_route(state["query"])
    return {"route": route}

def route_edge(state: QueryState) -> str:
    return state["route"]

def tax_handler(state: QueryState) -> QueryState:
    response = tax_chain.invoke({"question": state["query"]})
    return {"response": response}

def legal_handler(state: QueryState) -> QueryState:
    response = legal_chain.invoke({"question": state["query"]})
    return {"response": response}

def hr_handler(state: QueryState) -> QueryState:
    response = hr_chain.invoke({"question": state["query"]})
    return {"response": response}

def fallback_handler(state: QueryState) -> QueryState:
    return {"response": "I can help with tax, legal, or HR questions. Which area does your question relate to?"}

builder = StateGraph(QueryState)
builder.add_node("classify", classify_node)
builder.add_node("tax", tax_handler)
builder.add_node("legal", legal_handler)
builder.add_node("hr", hr_handler)
builder.add_node("fallback", fallback_handler)

builder.set_entry_point("classify")
builder.add_conditional_edges("classify", route_edge, {
    "tax": "tax",
    "legal": "legal",
    "hr": "hr",
    "fallback": "fallback",
})
for node in ["tax", "legal", "hr", "fallback"]:
    builder.add_edge(node, END)

graph = builder.compile()

