])
def test_routes_correctly(router, query, expected):
    result = route_by_centroid(query, router, embeddings)
    assert result == expected, f"Expected {expected!r} for {query!r}, got {result!r}"

def test_threshold_gate(router):
    # A borderline query with very low similarity should hit fallback
    result = route_by_centroid("hello", router, embeddings, threshold=0.80)
    assert result == "fallback"

def test_new_route_added(router):
    updated = add_route(router, "finance", [
        "What is dollar-cost averaging?",
        "How do index funds work?",
    ], embeddings)
    result = route_by_centroid("Should I invest in ETFs?", updated, embeddings)
    assert result == "finance"
